# JSON serializer/deserializer for Memcached
def json_serializer(key, value):
    if isinstance(value, str):
        return value.encode('utf-8'), 1
    return json.dumps(value).encode('utf-8'), 2


def json_deserializer(key, value, flags):
    if flags == 1:
        return value.decode('utf-8')
    if flags == 2:
        return json.loads(value.decode('utf-8'))
    return value


class MemcachedManager:
    """Thread-safe Memcached client manager with error handling."""

    def __init__(self, app_config):
        self._config = app_config
        self._client = None

    def _create_client(self):
        base_client = Client(
            (self._config['MEMCACHED_HOST'], self._config['MEMCACHED_PORT']),
            serializer=json_serializer,
            deserializer=json_deserializer,
            connect_timeout=self._config['MEMCACHED_CONNECT_TIMEOUT'],
            timeout=self._config['MEMCACHED_TIMEOUT'],
            no_delay=True,
            default_noreply=False,
        )
        return RetryingClient(
            base_client,
            attempts=3,
            retry_delay=0.1,
        )

    @property
    def client(self):
        if self._client is None:
            self._client = self._create_client()
        return self._client

    def get(self, key):
        try:
            sanitized_key = self._sanitize_key(key)
            return self.client.get(sanitized_key)
        except MemcacheError as e:
            logger.error(f"Memcached GET error for key '{key}': {e}")
            return None
        except Exception as e:
            logger.error(f"Unexpected error during Memcached GET: {e}")
            return None

    def set(self, key, value, ttl=None):
        try:
            sanitized_key = self._sanitize_key(key)
            expire = ttl if ttl is not None else self._config['DEFAULT_CACHE_TTL']
            # Validate TTL is reasonable (max 30 days)
            expire = min(max(0, expire), 2592000)
            return self.client.set(sanitized_key, value, expire=expire)
        except MemcacheError as e:
            logger.error(f"Memcached SET error for key '{key}': {e}")
            return False
        except Exception as e:
            logger.error(f"Unexpected error during Memcached SET: {e}")
            return False

    def delete(self, key):
        try:
            sanitized_key = self._sanitize_key(key)
            return self.client.delete(sanitized_key)
        except MemcacheError as e:
            logger.error(f"Memcached DELETE error for key '{key}': {e}")
            return False
        except Exception as e:
            logger.error(f"Unexpected error during Memcached DELETE: {e}")
            return False

    def incr(self, key, value=1):
        try:
            sanitized_key = self._sanitize_key(key)
            result = self.client.incr(sanitized_key, value)
            return result
        except MemcacheError as e:
            logger.error(f"Memcached INCR error for key '{key}': {e}")
            return None

    def add(self, key, value, ttl=None):
        """Set key only if it doesn't exist."""
        try:
            sanitized_key = self._sanitize_key(key)
            expire = ttl if ttl is not None else self._config['DEFAULT_CACHE_TTL']
            expire = min(max(0, expire), 2592000)
            return self.client.add(sanitized_key, value, expire=expire)
        except MemcacheError as e:
            logger.error(f"Memcached ADD error for key '{key}': {e}")
            return False

    def _sanitize_key(self, key):
        """Sanitize cache key to prevent injection and ensure valid format."""
        if not isinstance(key, str):
            key = str(key)
        # Hash the key to ensure safe characters and bounded length
        key_hash = hashlib.sha256(key.encode('utf-8')).hexdigest()
        # Prefix with a namespace for isolation
        sanitized = f"app:{key_hash}"
        if len(sanitized) > self._config['MAX_CACHE_KEY_LENGTH']:
            sanitized = sanitized[:self._config['MAX_CACHE_KEY_LENGTH']]
        return sanitized

    def close(self):
        if self._client is not None:
            try:
                self._client.close()
            except Exception as e:
                logger.error(f"Error closing Memcached connection: {e}")
            finally:
                self._client = None


