def generate_cache_key(*args, **kwargs):
    """Generate a deterministic cache key from arguments."""
    key_data = json.dumps({'args': args, 'kwargs': kwargs}, sort_keys=True, default=str)
    return hashlib.sha256(key_data.encode('utf-8')).hexdigest()


def cached_query(ttl=None):
    """Decorator to cache database query results."""
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = f"query:{func.__name__}:{generate_cache_key(*args, **kwargs)}"
            cached_result = cache.get(cache_key)
            if cached_result is not None:
                logger.info(f"Cache HIT for {func.__name__}")
                return cached_result

            logger.info(f"Cache MISS for {func.__name__}")
            result = func(*args, **kwargs)

            if result is not None:
                effective_ttl = ttl if ttl is not None else app.config['DEFAULT_CACHE_TTL']
                cache.set(cache_key, result, ttl=effective_ttl)

            return result
        return wrapper
    return decorator


def cached_response(ttl=None):
    """Decorator to cache API endpoint responses."""
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Build cache key from request details
            request_data = {
                'path': request.path,
                'method': request.method,
                'args': dict(request.args),
            }
            cache_key = f"response:{func.__name__}:{generate_cache_key(request_data)}"

            cached_result = cache.get(cache_key)
            if cached_result is not None:
                logger.info(f"Response cache HIT for {func.__name__}")
                response = jsonify(cached_result['data'])
                response.headers['X-Cache'] = 'HIT'
                return response

            logger.info(f"Response cache MISS for {func.__name__}")
            result = func(*args, **kwargs)

            # Cache the response data
            if isinstance(result, tuple):
                response_data, status_code = result[0], result[1] if len(result) > 1 else 200
            else:
                response_data = result
                status_code = 200

            # Only cache successful responses
            if status_code == 200:
                if hasattr(response_data, 'get_json'):
                    data_to_cache = response_data.get_json()
                elif isinstance(response_data, dict):
                    data_to_cache = response_data
                else:
                    data_to_cache = response_data

                effective_ttl = ttl if ttl is not None else app.config['DEFAULT_CACHE_TTL']
                cache.set(cache_key, {'data': data_to_cache}, ttl=effective_ttl)

            if isinstance(result, tuple):
                response = jsonify(response_data) if isinstance(response_data, dict) else response_data
                response.headers['X-Cache'] = 'MISS'
                return response, status_code
            else:
                if isinstance(response_data, dict):
                    response = jsonify(response_data)
                else:
                    response = response_data
                response.headers['X-Cache'] = 'MISS'
                return response

        return wrapper
    return decorator


def rate_limit(func):
    """Rate limiting decorator using Memcached."""
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        # Use IP address for rate limiting
        client_ip = request.remote_addr or 'unknown'
        # Sanitize IP for use in key
        rate_key = f"rate_limit:{client_ip}:{func.__name__}"
        window = app.config['RATE_LIMIT_WINDOW']
        limit = app.config['API_RATE_LIMIT']

        current_count = cache.get(rate_key)
        if current_count is None:
            # First request in window
            cache.set(rate_key, "1", ttl=window)
        else:
            try:
                count = int(current_count)
            except (ValueError, TypeError):
                count = 0

            if count >= limit:
                logger.warning(f"Rate limit exceeded for {client_ip} on {func.__name__}")
                return jsonify({
                    'error': 'Rate limit exceeded',
                    'retry_after': window
                }), 429

            result = cache.incr(rate_key)
            if result is None:
                # Key might have expired between get and incr, reset
                cache.set(rate_key, "1", ttl=window)

        return func(*args, **kwargs)
    return wrapper


def validate_positive_int(value, name="parameter"):
    """Validate that a value is a positive integer."""
    try:
        int_val = int(value)
        if int_val <= 0:
            raise ValueError
        return int_val
    except (ValueError, TypeError):
        abort(400, description=f"Invalid {name}: must be a positive integer")


def validate_string(value, name="parameter", max_length=255):
    """Validate and sanitize a string parameter."""
    if not isinstance(value, str):
        abort(400, description=f"Invalid {name}: must be a string")
    value = value.strip()
    if not value:
        abort(400, description=f"Invalid {name}: must not be empty")
    if len(value) > max_length:
        abort(400, description=f"Invalid {name}: exceeds maximum length of {max_length}")
    return value


